TDF = op.TDModules.mod.TDFunctions
popDialog = op.TDResources.op('popDialog')

class AutoUIExt:
	"""
	AutoUIExt description
	"""
	def __init__(self, ownerComp):
		self.ownerComp = ownerComp
		self.widgetTable = ownerComp.op('widgets')
		self.uiDict = None
		self.checkForUIDAT(raiseException=False)

	def openShortcutDialog(self):
		popDialog.OpenDefault\
				("Enter a parent shortcut for " + self.CustomComp.name,
					   "Missing Parent Shortcut",
					   ["Apply", "Skip", "Cancel"],
					   self.handleShortcutDialog,
					   textEntry = "Tox",
					   escButton=3, enterButton=1)

	def handleShortcutDialog(self, info):
		if info['button'] == 'Cancel':
			return
		elif info['button'] == 'Skip':
			self.GenerateUI(shortcutDialog=False)
		elif info['button'] == 'Apply':
			if not info['enteredText']:
				self.openShortcutDialog()
				return
			else:
				self.CustomComp.par.parentshortcut = \
											tdu.legalName(info['enteredText'])
				self.GenerateUI()

	def GenerateUI(self, customComp=None, ui=None, shortcutDialog=True):
		self.checkForUIDAT()
		if customComp is None:
			customComp = self.CustomComp
		if not customComp or customComp == root:
			error = "Invalid Auto UI custom component."
			popDialog.OpenDefault(error, 'Invalid Component')
			self.ownerComp.addScriptError(error)
			raise Exception(error)

		self.ownerComp.clearScriptErrors()
		self.uiDict = self.buildUIDict()

		if not customComp.par.parentshortcut and shortcutDialog:
			self.openShortcutDialog()
			return
		if ui is None:
			ui = self.ownerComp.par.Ui.eval()
		self.uiDict = self.buildUIDict()
		# if self.ownerComp.par.Ui:
		# 	self.ownerComp.par.Ui.eval().destroy()
		# 	return

		widgetParInfo = {}
		# set up ui layout
		if ui:
			if ui == op('/ui'):
				error = "Invalid Auto UI target: /ui"
				self.ownerComp.addScriptError(error)
				raise Exception(error)
			# get all widget parameters
			for widget in ui.findChildren(type=widgetCOMP):
				widgetParInfo[widget.path] = TDF.getParInfo(widget)
			# clear out ui
			for o in ui.children:
				o.destroy()
		else:
			if self.ownerComp.par.Ui.val \
							and self.ownerComp.par.Ui.mode == ParMode.CONSTANT:
				name = self.ownerComp.par.Ui.val
			else:
				name = 'ui'
			try:
				ui = customComp.copy(self.autoWidget('*Layout'), name=name)
				ui.par.Widgetmode = 'interact'
				ui.par.Popuphelp = ''
				ui.par.stdswitcher = 8
			except:
				ui = customComp.create(containerCOMP, name)
				ui.viewer = True
			self.ownerComp.par.Ui = ui
			ui.nodeX = self.ownerComp.nodeX + 200
			ui.nodeY = self.ownerComp.nodeY
			ui.par.phscrollbar = 'auto'
			ui.par.pvscrollbar = 'auto'
			ui.par.align = 'verttb'
			if isinstance(customComp, PanelCOMP):
				ui.par.hmode = 'fill'
				ui.par.vmode = 'fill'
			else:
				ui.par.hmode = 'fixed'
				ui.par.vmode = 'fixed'
				ui.par.sizefromwindow = True
				ui.par.vieweraspect = 'unconstrained'

		# create parList - list of first par in every tuplet
		pageList = tdu.match( self.ownerComp.par.Pagescope.eval(),
							  [p.name for p in customComp.customPages])
		parList = customComp.pars(self.ownerComp.par.Parameterscope.eval())
		# if not self.ownerComp.par.Builtinpars:

		# get first par in tuplet only, and only chosen pages
		parList = [p for p in parList if p.isCustom and
				   		p.name == p.tuplet[0].name and p.page in pageList]

		# header
		if self.ownerComp.par.Header:
			widget = self.addWidget('*Header', customComp=customComp, ui=ui)
			widget.par.Headerlabel = customComp.name
			widget.par.Popuphelp = ''
			widget.par.alignorder = -2
			widget.nodeX = 0
			widget.nodeY = 400

		#pages
		if self.ownerComp.par.Pagetabs and len(customComp.customPages) > 1:
			pageWidget = self.addWidget('*Pages', customComp=customComp, ui=ui)
			pages = []
			for p in parList:
				if p.page not in pages:
					pages.append(p.page)
			pageWidget.par.Popuphelp = ''
			pageWidget.par.alignorder = -1
			pageWidget.par.Menunames = ''
			pageWidget.par.bgcolorr = pageWidget.par.bgcolorg = \
												pageWidget.par.bgcolorb = 0.1
			pageWidget.nodeX = 0
			pageWidget.nodeY = -200

			for page in pages:
				if isinstance(ui, widgetCOMP):
					pageLayout = self.addWidget('*Layout', name=page.name,
												customComp=customComp, ui=ui)
					pageLayout.par.Popuphelp = ''
				else:
					pageLayout = ui.create(containerCOMP, 'page1')
					pageLayout.viewer = True
					pageLayout.nodeX = 200 * (pageLayout.digits - 1)
					pageLayout.nodeY = 0


				pageLayout.par.hmode = 'fill'
				pageLayout.par.vmode = 'fill'
				pageLayout.par.align = 'verttb'
				pageLayout.par.phscrollbar = 'auto'
				pageLayout.par.pvscrollbar = 'auto'
				pageLayout.par.display.expr = "op('" + pageWidget.name + \
							"').par.Value0.eval() == me.name"
				if pageWidget.par.Menunames:
					pageWidget.par.Menunames = pageWidget.par.Menunames + ' ' +\
											   pageLayout.name
					pageWidget.par.Menulabels = pageWidget.par.Menulabels + ' '\
												+ page.name
				else:
					pageWidget.par.Menunames = pageLayout.name
					pageWidget.par.Menulabels = page.name

				#pars in pages
				for i, p in enumerate([p for p in parList if p.page == page]):
					widget = self.addWidget(p, p.name, pageLayout,
											customComp=customComp, ui=ui)
					widget.par.alignorder = i
					widget.nodeX = 0
					widget.nodeY = i * -200
		else:
			for i, p in enumerate(parList):
				widget = self.addWidget(p, p.name, customComp=customComp, ui=ui)
				widget.par.alignorder = i
				widget.nodeX = 0
				widget.nodeY = i * -200
		for widget in ui.findChildren(type=widgetCOMP):
			if widget.path in widgetParInfo:
				TDF.applyParInfo(widget, widgetParInfo[widget.path])

	@staticmethod
	def widgetKey(par):
		if Page.styles[par.style].sizeable:
			return par.style + (' ' + str(len(par.tuplet)) \
												if len(par.tuplet) > 1 else '')
		else:
			return par.style

	def addWidget(self, parOrKey, name=None, pageLayout=None, par=None,
				  customComp=None, ui=None):
		if customComp is None:
			customComp = self.CustomComp
		if ui is None:
			ui = self.ownerComp.par.Ui.eval()
		if ui is None:
			raise Exception('addWidget - no UI found')

		# key
		if isinstance(parOrKey, str):
			widgetKey = parOrKey
			par = None
		else:
			widgetKey = self.widgetKey(parOrKey)
			par = parOrKey

		# generate widget
		widgetSource = self.autoWidget(widgetKey)
		if widgetSource is None:
			print("addWidget error: widget not found for", parOrKey,
											  "(" + self.ownerComp.path + ")" )
			return
		if pageLayout is not None:
			widget = pageLayout.copy(widgetSource, name=par.tupletName
														if par else name)
			if isinstance(ui, widgetCOMP):
				pageLayout.AddWidget(widget, customComp=customComp, ui=ui)
		else:
			widget = ui.copy(widgetSource, name=name)
			if isinstance(ui, widgetCOMP):
				ui.AddWidget(widget, customComp=customComp, ui=ui)
		# set up widget
		widget.par.hmode = 'fill'
		widget.par.vmode = 'constant'
		widget.par.Popuphelp = ''
		if par is not None:
			widget.par.Widgetlabel = par.label
			if par.isMenu and hasattr(widget.par, 'Menunames'):
				widget.par.Menunames.expr = 'me.par.Value0.bindMaster.menuNames'
			if par.isMenu and hasattr(widget.par, 'Menulabels'):
				widget.par.Menulabels.expr = \
										'me.par.Value0.bindMaster.menuLabels'
			suffixes = Page.styles[par.style].suffixes
			numValues = 0
			for v in range(4):
				if getattr(widget.par, 'Value' + str(v), None) is not None:
					numValues += 1
			for v in range(numValues):
				valuePar = getattr(widget.par, 'Value' + str(v), None)
				if valuePar is not None:
					valuePar.bindExpr = TDF.getShortcutPath(widget,
							customComp) + '.par.' + par.tuplet[v].name
					setattr(widget.par, 'Valname' + str(v),
							par.label + (' ' + str(v) if numValues > 1 else ''))
					matchProps = ['min', 'max', 'normMin', 'normMax',
								  'clampMin', 'clampMax', 'default']
					for prop in matchProps:
						setattr(valuePar, prop, getattr(par.tuplet[v], prop))
			if suffixes[0] and suffixes[0] != '1':
				for i, suffix in enumerate(suffixes):
					namePar = getattr(widget.par, 'Valname' + str(i), None)
					if namePar is not None:
						namePar.val = suffix.capitalize()
			widgetSettings = self.autoWidgetSettings(widgetKey)
			for p, e in widgetSettings.items():
				getattr(widget.par, p).val = eval(e)

		return widget

	@property
	def CustomComp(self):
		return self.ownerComp.par.Customcomp.eval()

	@property
	def Package(self):
		return self.ownerComp.par.Package.eval()

	@property
	def WidgetKit(self):
		return self.ownerComp.par.Package.eval().Kit(
				TDF.getMenuLabel(self.ownerComp.par.Widgetkit))

	@property
	def EmptyMenu(self):
		return TDF.parMenu([])


	def autoWidget(self, key):
		if self.uiDict is None:
			self.uiDict = self.buildUIDict()
		return self.ownerComp.par.Widgetcontainer.eval().op(self.uiDict[key][0])

	def autoWidgetSettings(self, key):
		if self.uiDict is None:
			self.uiDict = self.buildUIDict()
		return self.uiDict[key][1]

	def checkForUIDAT(self, raiseException=True):
		try:
			uiDAT = self.ownerComp.par.Autouidat.eval()
		except:
			uiDAT = None
		if not uiDAT:
			message = "AutoUI requires a widget package. For "\
								  "standard usage, add Palette> UI>\n"\
								  "Basic Widgets> Package> basicWidgets to "\
								  "project."
			popDialog.OpenDefault(message, "Widget Package Required")
			if raiseException:
				raise Exception(message)
			else:
				print(message)
		return uiDAT

	def buildUIDict(self):
		uiDAT = self.checkForUIDAT()
		uiDict = {}
		for rowNum in range(1, uiDAT.numRows):
			parType = uiDAT[rowNum, 'Parameter Style'].val
			size = uiDAT[rowNum, 'Size'].val
			if size:
				parType += ' ' + size
			widgetName = uiDAT[rowNum, 'Widget Name'].val
			settings = uiDAT[rowNum, 'Settings Dict'].val
			if settings:
				settings = eval(settings)
			else:
				settings = {}
			uiDict[parType] = (widgetName, settings)
		return uiDict

	def onParValueChange(self, par, prev):
		if par.name == 'Usewidgetpackage':
			self.ownerComp.par.Package.enable = par.eval()
			self.ownerComp.par.Widgetkit.enable = par.eval()
			if par.eval():
				self.ownerComp.par.Autouidat.expr = \
										"me.WidgetKit.op('resources/autoUI')"
				self.ownerComp.par.Widgetcontainer.expr = \
										"me.WidgetKit.op('widgets')"
			else:
				self.ownerComp.par.Autouidat.expr = \
											"op.TDBasicWidgets.op('autoUI')"
				self.ownerComp.par.Widgetcontainer.expr = \
											"op.TDBasicWidgets"

	def onParPulse(self, par):
		if par.name == 'Generateui':
			self.GenerateUI()
